local ADDON_NAME, CCO = ...

CCO.RecipeDB = {}

--- Returns the recipe list for a given WoW skillLine ID.
-- @param skillLineID  number  (e.g. 171 for Alchemy)
-- @return table
function CCO:GetRecipesForSkill(skillLineID)
    return CCO.RecipeDB[skillLineID] or {}
end

--- Searches all recipes for a name substring (case-insensitive).
-- @param query  string
-- @return table  list of {skillLineID, recipe} pairs
function CCO:SearchRecipes(query)
    local results = {}
    local lower = query:lower()
    for skillLineID, recipes in pairs(CCO.RecipeDB) do
        for _, r in ipairs(recipes) do
            if r.name:lower():find(lower, 1, true) then
                table.insert(results, { skillLineID = skillLineID, recipe = r })
            end
        end
    end
    return results
end

